SELECT id, report_name, report_code, data_source_id, sql_content, params, description, status, mobile_enabled, report_type, allow_export_excel, allow_export_pdf, allow_print, pdf_watermark, watermark_type, create_by, create_time, update_time FROM report_definition
AND (report_name LIKE CONCAT('%', #{keyword}, '%') OR report_code LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY create_time DESC LIMIT #{pageSize} OFFSET #{offset}

