report_name = #{reportName}, report_code = #{reportCode}, data_source_id = #{dataSourceId}, sql_content = #{sqlContent}, params = #{params}, description = #{description}, status = #{status}, report_type = #{reportType}, allow_export_excel = #{allowExportExcel}, allow_export_pdf = #{allowExportPdf}, allow_print = #{allowPrint}, pdf_watermark = #{pdfWatermark}, watermark_type = #{watermarkType}, update_time = NOW()
